  // Build case-insensitive lookup sets for the tokenizer.
  var keywordSet = new Set(keywords);
  var builtinSet = new Set(builtinFunctions);

  // ── Monarch tokenizer ──
  monaco.languages.setMonarchTokensProvider('duckdb-sql', {
    ignoreCase: true,
    defaultToken: '',

    keywords: keywords,
    builtinFunctions: builtinFunctions,
    keywordOrFunction: keywordOrFunction,

    operators: [
      '=',
      '>',
      '<',
      '!',
      '~',
      '?',
      ':',
      '==',
      '<=',
      '>=',
      '!=',
      '<>',
      '&&',
      '||',
      '++',
      '--',
      '+',
      '-',
      '*',
      '/',
      '&',
      '|',
      '^',
      '%',
      '<<',
      '>>',
      '>>>',
      '+=',
      '-=',
      '*=',
      '/=',
      '&=',
      '|=',
      '^=',
      '%=',
      '<<=',
      '>>=',
      '>>>=',
      '::',
      '->',
      '->>',
    ],

    // C-like escapes (for completeness, though SQL uses '' for escaping)
    escapes: /\\(?:[abfnrtv\\"']|x[0-9A-Fa-f]{1,4}|u[0-9A-Fa-f]{4}|U[0-9A-Fa-f]{8})/,

    tokenizer: {
      root: [
        // Block comments
        [/\/\*/, 'comment.sql', '@comment'],

        // Line comments
        [/--.*$/, 'comment.sql'],

        // Whitespace
        { include: '@whitespace' },

        // Dollar-quoted strings: $$...$$
        [/\$\$/, 'string.sql', '@dollarString'],

        // Numbered parameters: $1, $2, ...
        [/\$[0-9]+/, 'variable.sql'],

        // Single-quoted strings
        [/'/, 'string.sql', '@string'],

        // Double-quoted identifiers
        [/"/, 'identifier.quote.sql', '@quotedIdentifier'],

        // Numbers (hex, float, int)
        [/0[xX][0-9a-fA-F]+/, 'number.hex.sql'],
        [/[0-9]+(\.[0-9]+)?([eE][+-]?[0-9]+)?/, 'number.sql'],

        // Identifiers followed by '(' — dual-purpose keywords act as functions
        [
          /[a-zA-Z_][a-zA-Z0-9_]*(?=\s*\()/,
          {
            cases: {
              '@keywordOrFunction': 'predefined.sql',
              '@builtinFunctions': 'predefined.sql',
              '@keywords': 'keyword.sql',
              '@default': 'identifier.sql',
            },
          },
        ],

        // Identifiers not followed by '('
        [
          /[a-zA-Z_][a-zA-Z0-9_]*/,
          {
            cases: {
              '@keywords': 'keyword.sql',
              '@builtinFunctions': 'predefined.sql',
              '@default': 'identifier.sql',
            },
          },
        ],

        // Operators
        [/[<>=!~?:&|+\-*\/^%]+/, 'operator.sql'],

        // Delimiters
        [/[;,.]/, 'delimiter.sql'],
        [/[()\[\]]/, 'delimiter.bracket.sql'],
      ],

      comment: [
        [/[^/*]+/, 'comment.sql'],
        [/\*\//, 'comment.sql', '@pop'],
        [/[/*]/, 'comment.sql'],
      ],

      string: [
        [/[^']+/, 'string.sql'],
        [/''/, 'string.escape.sql'],
        [/'/, 'string.sql', '@pop'],
      ],

      dollarString: [
        [/[^$]+/, 'string.sql'],
        [/\$\$/, 'string.sql', '@pop'],
        [/\$/, 'string.sql'],
      ],

      quotedIdentifier: [
        [/[^"]+/, 'identifier.quote.sql'],
        [/""/, 'identifier.quote.sql'],
        [/"/, 'identifier.quote.sql', '@pop'],
      ],

      whitespace: [[/\s+/, 'white']],
    },
  });

  // Signal that the DuckDB language is registered.
  window._datatealLanguageReady = true;
  if (window._datatealLanguageResolve) window._datatealLanguageResolve();
